def parse_value(buf, at):
    """Decode one value; returns (python value, next offset)."""
    vtype, vlen = struct.unpack_from("<II", buf, at)
    payload = buf[at + 8:at + 8 + vlen]
    end = at + 8 + ((vlen + 7) & ~7)
    if vtype == VALUE_BOOL:
        return payload[0] != 0, end
    if vtype == VALUE_I64:
        return struct.unpack("<q", payload)[0], end
    if vtype == VALUE_F64:
        return struct.unpack("<d", payload)[0], end
    if vtype == VALUE_STR:
        return payload.decode(), end
    if vtype == VALUE_BLOB:
        return BlobHandle(struct.unpack("<Q", payload)[0]), end
    raise ValueError(f"unknown value type {vtype}")


def parse_occurrence(buf):
    """Decode one occurrence record (header included).

    Returns (kind, id, keys, payload). keys is [] when id is a
    widget id, else id is a template node id and keys is the
    copy's key path. text is the entry's new content for
    OCC_TEXT_CHANGED, the new state for OCC_TOGGLED, the new
    value for OCC_VALUE_CHANGED, None otherwise.
    """
    _size, kind, _flags = struct.unpack_from("<IHH", buf, 0)
    if kind not in (OCC_BUTTON_CLICKED, OCC_TEXT_CHANGED, OCC_TOGGLED, OCC_VALUE_CHANGED, OCC_CLOSE_REQUESTED, OCC_WINDOW_CLOSED):
        return kind, None, [], None
    if kind in (OCC_CLOSE_REQUESTED, OCC_WINDOW_CLOSED):
        # Window lifecycle records carry the window id alone —
        # no key path, no payload.
        (window_id,) = struct.unpack_from("<Q", buf, 8)
        return kind, window_id, [], None
    ident, path_len = struct.unpack_from("<QI", buf, 8)
    keys = []
    at = 24
    for _ in range(path_len):
        key, at = parse_value(buf, at)
        keys.append(key)
    payload = None
    if kind in (OCC_TEXT_CHANGED, OCC_TOGGLED, OCC_VALUE_CHANGED,):
        payload, at = parse_value(buf, at)
    return kind, ident, keys, payload
